import { create } from 'zustand';
import { devtools, persist, createJSONStorage } from 'zustand/middleware';
import { immer } from 'zustand/middleware/immer';
import storage from '../redux/store/storage';
import { RewardProgramRootStore, setSlicesRewardProgram,  } from './slices';


export const useRootStore = create<RewardProgramRootStore>()(
  devtools(
    persist(
      immer((...a) => ({
        ...setSlicesRewardProgram(...a),
      })),
      {
        name: 'root-storage',
        storage: createJSONStorage(() => storage),
        partialize: (s) => ({
          parameterPointsProgram: s.parameterPointsProgram,
        }),
        merge: (persisted, current) => ({ ...current, ...(persisted as Partial<RewardProgramRootStore>) }),
      }
    ),
    { name: 'RootStore' }
  )
);
export { RewardProgramRootStore };

import { StateCreator } from "zustand";
import {
  createParameterPointsProgramSlice,
  createPointsExtractSlice,
  ParameterPointsProgramSlice,
  PointsExtractSlice,
  createAirlineMilesSlice,
  AirlineMilesSlice,
  createMarketplaceSlice,
  MarketplaceSlice,
  createInvoiceCashbackPermissionSlice,
  InvoiceCashbackPermissionSlice,
  createPointsProductsSlice,
  PointsProductsSlice,
  createRescueSlice,
  RescueSlice,
} from "../services/store";

export type RewardProgramRootStore =
  ParameterPointsProgramSlice &
  PointsExtractSlice &
  AirlineMilesSlice &
  MarketplaceSlice &
  InvoiceCashbackPermissionSlice &
  PointsProductsSlice &
  RescueSlice;
export type Slice<T> = StateCreator<RewardProgramRootStore, [], [], T>;
export const asSlice = <T>(slice: StateCreator<RewardProgramRootStore, [], [], T>) => slice as Slice<T>;

export function setSlicesRewardProgram<T extends RewardProgramRootStore>(...a: Parameters<Slice<T>>) {
  return {
    ...asSlice<PointsExtractSlice>(createPointsExtractSlice)(...a),
    ...asSlice<ParameterPointsProgramSlice>(createParameterPointsProgramSlice)(...a),
    ...asSlice<AirlineMilesSlice>(createAirlineMilesSlice)(...a),
    ...asSlice<MarketplaceSlice>(createMarketplaceSlice)(...a),
    ...asSlice<InvoiceCashbackPermissionSlice>(createInvoiceCashbackPermissionSlice)(...a),
    ...asSlice<PointsProductsSlice>(createPointsProductsSlice)(...a),
    ...asSlice<RescueSlice>(createRescueSlice)(...a),
  };
}

